from __future__ import annotations

from dataclasses import asdict, is_dataclass
import json
from pathlib import Path

from qis.spot_forecast import SpotForecast


def render_spot_dashboard(forecasts: list[SpotForecast | dict], output: Path) -> Path:
    payload = json.dumps(
        [asdict(item) if is_dataclass(item) else item for item in forecasts],
        ensure_ascii=False,
    )
    return _write_dashboard(payload, output)


def render_spot_dashboard_cache(cache_path: Path, output: Path) -> Path | None:
    if not cache_path.exists():
        return None
    rows = json.loads(cache_path.read_text(encoding="utf-8"))
    if not isinstance(rows, list) or not rows:
        return None
    payload = json.dumps(rows, ensure_ascii=False)
    return _write_dashboard(payload, output)


def _write_dashboard(payload: str, output: Path) -> Path:
    output.parent.mkdir(parents=True, exist_ok=True)
    output.write_text(HTML.replace("__FORECAST_DATA__", payload), encoding="utf-8")
    output.with_name("spot_forecasts.json").write_text(payload, encoding="utf-8")
    return output


